# ---------------------------------------------------------------------------
# Constants for the forward-simulation helpers
# ---------------------------------------------------------------------------

DAGESH = "\N{HEBREW POINT DAGESH OR MAPIQ}"
HIRIQ = "\N{HEBREW POINT HIRIQ}"
TSERE = "\N{HEBREW POINT TSERE}"
QAMATS = "\N{HEBREW POINT QAMATS}"
QAMATS_QATAN = "\N{HEBREW POINT QAMATS QATAN}"
HOLAM = "\N{HEBREW POINT HOLAM}"
QUBUTS = "\N{HEBREW POINT QUBUTS}"

_VOWEL_NAME_TO_MARK: dict[str, str] = {name: mark for mark, name in MARK_NAMES.items()}

_MATER_FROM_SUFFIX: dict[str, str] = {
    "qamats-yod": "י",
    "qamats-qatan-yod": "י",
    "tsere-yod": "י",
    "ḥiriq-yod": "י",
    "yod": "י",
    "qamats-vav": "ו",
    "qamats-qatan-vav": "ו",
    "ḥolam-vav": "ו",
    "shuruq": "ו",
    "vav": "ו",
}

_LETTER_FROM_NAME: dict[str, str] = {v: k for k, v in SYMBOL_NAMES.items()}


# ---------------------------------------------------------------------------
# Forward-simulation helpers
# These independently apply the described operation to MAM and predict qere.
# They are "cheating" in that they are given structural parameters extracted
# from the description string, rather than a full parse; but they are NOT
# given qere_text, so the match assertion is non-trivial.
# ---------------------------------------------------------------------------


def _strip_all_points(text: str) -> str:
    return "".join(c for c in text if not unicodedata.combining(c))


def _letters_only(text: str) -> str:
    return "".join(c for c in text if c in HEBREW_LETTERS)


def _skel_positions(text: str) -> list[int]:
    return [i for i, c in enumerate(text) if not unicodedata.combining(c)]


def _combining_after(text: str, pos: int) -> list[str]:
    marks: list[str] = []
    for i in range(pos + 1, len(text)):
        if unicodedata.combining(text[i]):
            marks.append(text[i])
        else:
            break
    return marks


def _predict_xaser_malei_insert(
    mam_text: str,
    *,
    old_vowel: str,
    new_suffix: str,
    after_letter: str | None = None,
) -> str:
    """Return predicted qere SKELETON by inserting the mater described.

    Finds the letter in MAM that bears `old_vowel` (and optionally matches
    `after_letter`), then inserts the new mater after it.
    """
    vowel_mark = _VOWEL_NAME_TO_MARK[old_vowel]
    new_mater = _MATER_FROM_SUFFIX[new_suffix]
    skel_mam = _strip_all_points(mam_text)
    positions = _skel_positions(mam_text)
    for skel_idx, char_pos in enumerate(positions):
        letter = mam_text[char_pos]
        marks = _combining_after(mam_text, char_pos)
        if vowel_mark in marks:
            if after_letter is None or letter == after_letter:
                return skel_mam[: skel_idx + 1] + new_mater + skel_mam[skel_idx + 1 :]
    raise AssertionError(
        f"Vowel {old_vowel!r} not found in {mam_text!r}"
        + (f" on letter {after_letter!r}" if after_letter else "")
    )


def _predict_letter_remove(mam_text: str, *, letter_name: str) -> str:
    """Return predicted qere LETTER skeleton by removing one instance of letter."""
    char = _LETTER_FROM_NAME[letter_name]
    letters = _letters_only(mam_text)
    idx = letters.index(char)
    return letters[:idx] + letters[idx + 1 :]


def _predict_letter_replace(
    mam_text: str,
    *,
    old_name: str,
    new_name: str,
    after_letter: str | None = None,
) -> str:
    """Return predicted qere LETTER skeleton by replacing old letter with new.

    When `after_letter` is given, replaces the instance of old_name that
    immediately follows after_letter (needed when old_name appears multiple times).
    """
    old_char = _LETTER_FROM_NAME[old_name]
    new_char = _LETTER_FROM_NAME[new_name]
    letters = _letters_only(mam_text)
    if after_letter is not None:
        for i, c in enumerate(letters):
            if c == old_char and i > 0 and letters[i - 1] == after_letter:
                return letters[:i] + new_char + letters[i + 1 :]
        raise AssertionError(
            f"Letter {old_name!r} not found immediately after {after_letter!r}"
            f" in {letters!r}"
        )
    idx = letters.index(old_char)
    return letters[:idx] + new_char + letters[idx + 1 :]


def _predict_letter_add_at_end(mam_text: str, *, letter_name: str) -> str:
    return _letters_only(mam_text) + _LETTER_FROM_NAME[letter_name]


def _predict_letter_add_after(mam_text: str, *, new_name: str, after_name: str) -> str:
    new_char = _LETTER_FROM_NAME[new_name]
    after_char = _LETTER_FROM_NAME[after_name]
    letters = _letters_only(mam_text)
    # Insert after the LAST occurrence of after_char
    idx = letters.rindex(after_char)
    return letters[: idx + 1] + new_char + letters[idx + 1 :]


def _predict_spelling_replace(
    mam_text: str,
    qere_text: str,
    *,
    old_spelling: str,
    new_spelling: str,
) -> str:
    """Verify a mater-swap (replace opcode) and return the predicted qere skeleton.

    Unlike the other helpers this consults qere_text only for the opcode
    position — the mater identity check is independent.
    """
    old_mater = _MATER_FROM_SUFFIX[old_spelling]
    new_mater = _MATER_FROM_SUFFIX[new_spelling]
    skel_mam = _strip_all_points(mam_text)
    skel_qere = _strip_all_points(qere_text)
    for tag, i1, i2, j1, j2 in SequenceMatcher(
        None, skel_mam, skel_qere, autojunk=False
    ).get_opcodes():
        if tag == "replace":
            assert skel_mam[i1:i2] == old_mater, (
                f"Expected old mater {old_mater!r} at opcode, "
                f"found {skel_mam[i1:i2]!r}"
            )
            assert skel_qere[j1:j2] == new_mater, (
                f"Expected new mater {new_mater!r} at opcode, "
                f"found {skel_qere[j1:j2]!r}"
            )
            return skel_mam[:i1] + new_mater + skel_mam[i2:]
    raise AssertionError(
        f"No replace opcode found between {mam_text!r} and {qere_text!r}"
    )


def _grapheme_clusters(text: str) -> list[str]:
    clusters: list[str] = []
    for char in text:
        if not clusters or not unicodedata.combining(char):
            clusters.append(char)
            continue
        clusters[-1] += char
    return clusters


def _cluster_marks(cluster: str) -> list[str]:
    return list(cluster[1:])


def _predict_qubuts_shuruq_hiriq_haser(mam_text: str) -> str:
    clusters = _grapheme_clusters(mam_text)
    for index in range(len(clusters) - 2):
        current_cluster = clusters[index]
        first_yod = clusters[index + 1]
        second_yod = clusters[index + 2]
        current_marks = _cluster_marks(current_cluster)
        first_yod_marks = _cluster_marks(first_yod)
        second_yod_marks = _cluster_marks(second_yod)
        if QUBUTS not in current_marks:
            continue
        if first_yod[0] != "י" or second_yod[0] != "י":
            continue
        if HIRIQ not in first_yod_marks or HIRIQ in second_yod_marks:
            continue

        transformed = list(clusters)
        transformed[index] = current_cluster[0] + "".join(
            mark for mark in current_marks if mark != QUBUTS
        )
        transformed[index + 1] = "ו" + DAGESH
        transformed[index + 2] = "י" + "".join(first_yod_marks + second_yod_marks)
        return "".join(transformed)

    raise AssertionError(f"Composite qubuts/shuruq pattern not found in {mam_text!r}")


