class XaserMaleiInsertTests(unittest.TestCase):
    """xaser→malei: UXLC qere adds one mater lectionis that MAM lacks."""

    def test_tsere_to_tsere_yod(self) -> None:
        # Row 1 — unique tsere; "after bet" no longer emitted
        _assert_xaser_malei_insert(
            self,
            "וּבֵנָ֔יו",
            "וּבֵינָ֔יו",
            "replace tsere with tsere-yod",
            old_vowel="tsere",
            new_suffix="tsere-yod",
        )

    def test_qamats_to_qamats_yod_unique(self) -> None:
        # Row 4 — single qamats
        _assert_xaser_malei_insert(
            self,
            "חֲסִידָו֙",
            "חֲסִידָיו֙",
            "replace qamats with qamats-yod",
            old_vowel="qamats",
            new_suffix="qamats-yod",
        )

    def test_qamats_to_qamats_yod_after_nun(self) -> None:
        # Row 8 — two qamats in the word; "after nun" needed
        _assert_xaser_malei_insert(
            self,
            "בָּנָ֣ו",
            "בָּנָ֣יו",
            "replace qamats with qamats-yod after nun",
            old_vowel="qamats",
            new_suffix="qamats-yod",
            after_letter="נ",
        )

    def test_holam_to_holam_vav(self) -> None:
        # Row 23 — unique ḥolam; "after yod" no longer emitted
        _assert_xaser_malei_insert(
            self,
            "וְאַחְיֹתֵיהֶ֖ם",
            "וְאַחְיוֹתֵיהֶ֖ם",
            "replace ḥolam with ḥolam-vav",
            old_vowel="ḥolam",
            new_suffix="ḥolam-vav",
        )

    def test_qubuts_to_shuruq(self) -> None:
        # Row 39 — replaces qubuts (no mater) with shuruq (vav+dagesh)
        _assert_xaser_malei_insert(
            self,
            "מְשֻׁבוֹתֵיהֶֽם׃",
            "מְשׁוּבוֹתֵיהֶֽם׃",
            "replace qubuts with shuruq",
            old_vowel="qubuts",
            new_suffix="shuruq",
        )

    def test_hiriq_to_hiriq_yod(self) -> None:
        # Row 77 — unique ḥiriq; "after yod" no longer emitted
        _assert_xaser_malei_insert(
            self,
            "גּוֹיִ֖",
            "גּוֹיִ֖י",
            "replace ḥiriq with ḥiriq-yod",
            old_vowel="ḥiriq",
            new_suffix="ḥiriq-yod",
        )


class SpellingSwapTests(unittest.TestCase):
    """xaser↔malei where both spellings are meaningful (replace opcode at skeleton)."""

    def test_hiriq_yod_to_shuruq(self) -> None:
        # Row 25 — the pointed text combines two adjacent subchanges.
        mam = "בְּמַחֲלֻיִ֣ים"
        qere = "בְּמַחֲלוּיִ֣ם"
        expected = (
            "replace qubuts with shuruq; "
            "replace ḥiriq-yod with ḥiriq"
        )
        self.assertEqual(describe_xaser_malei_qere_change(mam, qere), expected)
        predicted = _predict_qubuts_shuruq_hiriq_haser(mam)
        self.assertEqual(predicted, qere)


